import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.File;
import java.io.FileReader;
import java.io.FileWriter; 
import java.io.IOException;
import java.lang.String;
import java.util.Arrays;

public class Ridge {
	static class Task {

		int n;
		int[] h, c;
		public void solve() {
			readInput();
			writeOutput(getResult());
		}

		private void readInput() {
			try {
				BufferedReader reader = 
					new BufferedReader(new FileReader("ridge.in"));

				String firstLine = reader.readLine();

				n = Integer.parseInt(firstLine);
				h = new int[n];
				c = new int[n];
				String[] line;

				for (int i = 0; i < n; i++) {
					line = reader.readLine().split(" "); 
					h[i] = Integer.parseInt(line[0]);
					c[i] = Integer.parseInt(line[1]);
				}

				reader.close();

			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(long result) {
			try {
				BufferedWriter buf = new BufferedWriter(new FileWriter("ridge.out"));
				buf.write(String.valueOf(result));
				buf.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}    
		private long getResult() {
			//the first column represents the index of the mountain we reached
			//the 2nd one is how many digs are being performed to mountain i
			//at most 2 digs
			long[][] dp = new long[n][3];

			//base case
			for (int j = 0; j < 3; j++) {
				dp[0][j] = j * c[0];
			}

			//general case
			for (int i = 1; i < n; i++) {
				for (int j = 0; j < 3; j++) {
					long min = 0;
					int foundMin = 0;
					//find the min value untill we reach mountain i
					for (int k = 0; k < 3; k++) {
						//the solutions where the heights of close montains are the same
						// and when Gigel would dig lower than 0 are excluded
						if (h[i] - j != h[i - 1] - k && h[i - 1] - k >= 0) {
							if (foundMin == 0) {
								min = dp[i - 1][k];
								foundMin = 1;
							} else
								if (dp[i - 1][k] < min) {
									min = dp[i - 1][k];
								}
						}
					}
					dp[i][j] = min + j * c[i];         
				}
			}
			long minResult = dp[n - 1][0];
			//the solution is the minimum from the dp[n-1] row
			for (int i = 0; i < 3; i++) {
				if (minResult > dp[n - 1][i]) {
					minResult = dp[n - 1][i];
				}
			}
			return minResult;
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}

#include <bits/stdc++.h>
using namespace std;

#define MAXIM 999999999999999

ifstream f("ridge.in");
ofstream g("ridge.out");

/* creez o structura pt perechea (Hi, Ci) */
struct pereche {
	long long Hi;
	long long Ci;
    /* creez constructorul */
	pereche(long long a, long long b) {
		Hi = a;
		Ci = b;
	}
};

/* declar un vector de perechi */
long long N;
vector<pereche> v;

/* citesc datele si le adaug in vector */
void citeste() {
	long long a, b;
	f >> N;
	for(int i = 0; i < N; i++) {
		f >> a >> b;
		v.push_back(pereche(a, b));
	}
	f.close();
}

/* functie ce calculeaza costul minim pt a obtine creasta dorita */
long long minimCost() {
    /* declar o matrice */
    vector<vector<long long> > mat(N, vector<long long>(3));
    int j;
    /* initializez prima linie din matrice */
    mat[0][0] = 0;
    mat[0][1] = v[0].Ci;
    mat[0][2] = v[0].Ci * 2;
    for (int i = 1; i < N; i++) {
        j = 0;
        while (j < 3) {
            long long minim = MAXIM;
            /* verific daca el curent e diferit de cel anterior */
            if (v[i].Hi - j != v[i - 1].Hi && (v[i].Hi - j >= 0)) {
                minim = min(minim, mat[i - 1][0]);
            }
            /*verific daca el curent e diferit de cel anterior 
            dupa ce am scazut 1 */
            if (v[i].Hi - j != v[i - 1].Hi - 1 &&  (v[i - 1].Hi - 1) >= 0
            	&& (v[i].Hi - j >= 0)) {
                minim = min(minim, mat[i - 1][1]);
            }
            /*verific daca el curent e diferit de cel anterior 
            dupa ce am scazut 2 */
             if (v[i].Hi -j != v[i - 1].Hi - 2 &&  (v[i - 1].Hi - 2) >= 0
             	&& (v[i].Hi - j >= 0)) {
                minim = min(minim, mat[i - 1][2]);
            }
            /* iau minimul din cele 3 cazuri */
            mat[i][j] = j * v[i].Ci + minim;
            j++;
        }
    }

    /* caut costul minim si il returnez */
    long long rez = MAXIM;
    for (int i = 0; i < 3; i++)
        rez = min(rez, mat[N - 1][i]);
    return rez;
}

int main() {
    /* citesc datele */
	citeste();
    long long rez = 0;
	rez = minimCost();
    /* scriu rezultatul in fisier */
	g << rez;
    return 0;
}
